#!/usr/bin/env node
/* global console, process */

import { spawn } from 'node:child_process';
import { existsSync, statSync, rmSync } from 'node:fs';
import path from 'node:path';
import { performance } from 'node:perf_hooks';
import { fileURLToPath } from 'node:url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);
const gnosisDir = path.resolve(__dirname, '../..');
const repoRoot = path.resolve(gnosisDir, '../..');

const playerBinary = path.resolve(
  repoRoot,
  'open-source/knotgraph/rust/target/release/squeezebox-player'
);

const testPhrases = [
  {
    id: 'short',
    label: 'Short Phrase ("Hello world.")',
    text: 'Hello world.',
  },
  {
    id: 'medium',
    label: 'Medium Sentence (Pangram)',
    text: 'The quick brown fox jumps over the lazy dog.',
  },
  {
    id: 'long',
    label: 'Long Paragraph (Formal Domain Zero)',
    text: 'Autonomic Architecture Zero represents a self-healing, formally verified, zero-intervention workspace and edge orchestration engine, ensuring total boundary protection and impenetrable manifold stability across the chromatic torus.',
  },
];

const configurations = [
  {
    name: 'Aeon Solo',
    args: ['--voice', 'aeon', '--no-play'],
    env: { SB_TURBULENCE: '0.0', SB_BREATH: '0.0' },
  },
  {
    name: 'Pleroma Solo',
    args: ['--voice', 'pleroma', '--no-play'],
    env: {},
  },
  {
    name: 'Sophia Solo',
    args: ['--voice', 'sophia', '--no-play'],
    env: {},
  },
  {
    name: 'Giant Steps Choir',
    args: ['--choir', '--no-play'],
    env: {},
  },
];

function readNumberSetting(flagName, envName, fallback) {
  const rawFlag = process.argv
    .slice(2)
    .find((value) => value.startsWith(`--${flagName}=`));
  const rawEnvValue = process.env[envName];
  const rawValue = rawFlag?.slice(flagName.length + 3) ?? rawEnvValue ?? `${fallback}`;
  const parsed = Number.parseInt(rawValue, 10);
  return Number.isFinite(parsed) && parsed > 0 ? parsed : fallback;
}

const warmupRuns = readNumberSetting('warmup', 'SB_BENCH_WARMUP', 2);
const measuredRuns = readNumberSetting('iterations', 'SB_BENCH_ITERATIONS', 5);

function percentile(sorted, ratio) {
  if (sorted.length === 0) return 0;
  const index = Math.min(sorted.length - 1, Math.max(0, Math.floor(sorted.length * ratio)));
  return sorted[index] ?? 0;
}

function summarize(samples) {
  const sorted = [...samples].sort((left, right) => left - right);
  const total = samples.reduce((sum, value) => sum + value, 0);
  return {
    meanMs: total / Math.max(1, samples.length),
    p50Ms: percentile(sorted, 0.5),
    p95Ms: percentile(sorted, 0.95),
    maxMs: sorted[sorted.length - 1] ?? 0,
  };
}

async function runCommand(command, args, extraEnv = {}) {
  return await new Promise((resolve) => {
    const child = spawn(command, args, {
      cwd: repoRoot,
      env: { ...process.env, ...extraEnv },
      stdio: ['ignore', 'pipe', 'pipe'],
    });

    let stdout = '';
    let stderr = '';

    child.stdout.setEncoding('utf8');
    child.stderr.setEncoding('utf8');
    child.stdout.on('data', (chunk) => { stdout += chunk; });
    child.stderr.on('data', (chunk) => { stderr += chunk; });

    child.once('error', (error) => {
      resolve({ exitCode: -1, stdout, stderr: String(error) });
    });

    child.once('close', (code) => {
      resolve({ exitCode: code ?? -1, stdout, stderr });
    });
  });
}

async function measureConfiguration(phrase, config) {
  const tempWavPath = `/tmp/sb_bench_${phrase.id}_${config.name.replace(/\s+/g, '_')}.wav`;
  rmSync(tempWavPath, { force: true });

  const envWithSttBypass = { ...config.env, SB_NO_STT: '1' };
  const fullArgs = [phrase.text, '-o', tempWavPath, ...config.args];

  // Warmups
  for (let run = 0; run < warmupRuns; run += 1) {
    const warmup = await runCommand(playerBinary, fullArgs, envWithSttBypass);
    if (warmup.exitCode !== 0) {
      throw new Error(`Warmup failed for ${config.name} / ${phrase.id}:\n${warmup.stderr}`);
    }
  }

  // Measured runs
  const samples = [];
  for (let run = 0; run < measuredRuns; run += 1) {
    rmSync(tempWavPath, { force: true });
    const started = performance.now();
    const result = await runCommand(playerBinary, fullArgs, envWithSttBypass);
    const elapsedMs = performance.now() - started;

    if (result.exitCode !== 0) {
      throw new Error(`Execution failed for ${config.name} / ${phrase.id}:\n${result.stderr}`);
    }
    samples.push(elapsedMs);
  }

  // Calculate audio duration from the generated WAV file size
  let audioDurationSec = 0.0;
  if (existsSync(tempWavPath)) {
    const stats = statSync(tempWavPath);
    const dataBytes = stats.size - 44; // Subtract WAV header
    const samplesCount = dataBytes / 2; // Mono PCM 16-bit
    audioDurationSec = samplesCount / 44100; // 44.1kHz
  }

  const summary = summarize(samples);
  const rtf = (summary.meanMs / 1000.0) / audioDurationSec;
  const speedup = 1.0 / rtf;

  rmSync(tempWavPath, { force: true });

  return { summary, audioDurationSec, rtf, speedup };
}

async function main() {
  if (!existsSync(playerBinary)) {
    throw new Error(`Missing squeezebox-player binary at ${playerBinary}. Please run cargo build --release first.`);
  }

  console.log('================================================================================');
  console.log('🔊 SQUEEZEBOX VOICE TTS SPEEDED BENCHMARK');
  console.log(`Warmups: ${warmupRuns} | Iterations: ${measuredRuns} | Sample Rate: 44100 Hz`);
  console.log('================================================================================');

  for (const phrase of testPhrases) {
    console.log(`\n📝 Phrase: ${phrase.label}`);
    console.log(`   "${phrase.text}"`);
    console.log('--------------------------------------------------------------------------------');
    console.log(
      'Configuration'.padEnd(20) + ' | ' +
      'Mean Latency'.padEnd(12) + ' | ' +
      'Audio Len'.padEnd(10) + ' | ' +
      'Real-Time Factor (RTF)'.padEnd(22) + ' | ' +
      'Speedup'
    );
    console.log('--------------------------------------------------------------------------------');

    for (const config of configurations) {
      try {
        const metrics = await measureConfiguration(phrase, config);
        console.log(
          config.name.padEnd(20) + ' | ' +
          `${metrics.summary.meanMs.toFixed(2)} ms`.padEnd(12) + ' | ' +
          `${metrics.audioDurationSec.toFixed(2)}s`.padEnd(10) + ' | ' +
          `RTF: ${metrics.rtf.toFixed(6)}`.padEnd(22) + ' | ' +
          `🚀 ${metrics.speedup.toFixed(1)}x real-time`
        );
      } catch (err) {
        console.log(config.name.padEnd(20) + ' | ' + `FAILED: ${err.message}`);
      }
    }
    console.log('================================================================================');
  }
}

main().catch((error) => {
  console.error(error);
  process.exit(1);
});
